exports.seed = async function (knex) {
  for (const [slug, langs] of Object.entries(UPAGRAHAS)) {
    const update = {};
    for (const [lang, f] of Object.entries(langs)) {
      update[`name_${lang}`] = f.name;
      update[`literal_meaning_${lang}`] = f.literal_meaning;
      update[`nature_${lang}`] = f.nature;
      update[`positive_traits_${lang}`] = f.positive_traits;
      update[`negative_traits_${lang}`] = f.negative_traits;
      update[`spiritual_${lang}`] = f.spiritual;
      update[`key_indication_${lang}`] = f.key_indication;
    }
    await knex('upagrahas').where({ slug }).update(update);
  }
  for (const [slug, house, langs] of HOUSE_EFFECTS) {
    const update = {};
    for (const [lang, txt] of Object.entries(langs)) update[`effect_${lang}`] = txt;
    await knex('upagraha_house_effects').where({ upagraha_slug: slug, house_number: house }).update(update);
  }
  for (const [slug, planet, langs] of CONJUNCTIONS) {
    const update = {};
    for (const [lang, txt] of Object.entries(langs)) update[`effect_${lang}`] = txt;
    await knex('upagraha_planet_conjunctions').where({ upagraha_slug: slug, planet_slug: planet }).update(update);
  }
};
